insert into public.cards (card_id, slug, bank_name, card_name, network, network_confidence, category, card_type, annual_fee, joining_fee, fee_waiver, forex_markup_pct, finance_charge_monthly_pct, finance_charge_annual_pct, cash_advance_fee, cash_interest, late_payment_fee, reward_summary, lounge_access, welcome_benefit, features, badge, apply_url, source_url, source_section, mitc_last_checked, data_status, match_status, is_lifetime_free, updated_at) values ('icici-mine-credit-card-by-icici-bank', 'icici-mine-credit-card-by-icici-bank', 'ICICI', 'Mine Credit Card by ICICI Bank', 'RuPay', 'medium', NULL, 'retail', NULL, NULL, 'Monthly plans: Starter Free Plan Nil; Pro 49 Plan Rs.49/month (reversed on spends of Rs.10,000 in plan cycle); Premium 149 Plan Rs.149/month (reversed on spends of Rs.20,000 in plan cycle). Charged monthly, not annually.', 3.5, 3.75, 45, 'On all cards - 2.5% on advanced amount, subject to minimum transaction fee of Rs.500. Exception: ICICI Bank Emeralde Private Metal Credit Card - Nil, ICICI Bank Emeralde Credit Card - Nil, ICICI Bank Emeralde Private Credit Card - Nil, Times Black ICICI Bank Credit Card - Nil', 'Finance charges for the revolving credit facility on retail transactions and cash advances = 3.75% per month i.e., 45% per annum. Interest is levied on all cash advances from the date of the transaction until the date of payment (no interest-free period on cash advances). The rate may vary at ICICI Bank''s discretion - as low as 1.25% per month (15% per annum) and, in case of default, up to a maximum of 3.75% per month (45% per annum).', 'Less than Rs.100: None; Between Rs.100-Rs.500: Rs.100; Between Rs.501-Rs.1,000: Rs.500; Between Rs.1,001-Rs.5,000: Rs.600; Between Rs.5,001-Rs.10,000: Rs.750; Between Rs.10,001-Rs.25,000: Rs.900; Between Rs.25,001-Rs.50,000: Rs.1,100; More than Rs.50,000: Rs.1,300 (excluding ICICI Bank Emeralde Private Metal Credit Card)', NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.icici.bank.in/managed-assets/do