insert into public.cards (card_id, slug, bank_name, card_name, network, network_confidence, category, card_type, annual_fee, joining_fee, fee_waiver, forex_markup_pct, finance_charge_monthly_pct, finance_charge_annual_pct, cash_advance_fee, cash_interest, late_payment_fee, reward_summary, lounge_access, welcome_benefit, features, badge, apply_url, source_url, source_section, mitc_last_checked, data_status, match_status, is_lifetime_free, updated_at) values ('federal-signet', 'federal-signet', 'Federal Bank', 'Signet', 'Visa', 'high', 'entry', 'retail', 750, 750, 'Spend Rs.75,000/- in current year and get a waiver on next year''s annual membership fee. (Joining fee waiver: Spend more than Rs. 10,000/- within first 3 Months and get the joining fee of Rs. 750/- waived off for the first year.) Above condition is not applicable for customers onboarded with effect from 03rd April 2023, since no fee is charged.', 3.5, 3.75, 45.0, '2.5% of amount withdrawn or Rs. 500 whichever is higher (Not applicable for Wave Credit Card)', 'All cash advances carry finance charges equal to the charges on revolving credit (Interest on Revolving Credit / APR, ranging from 23.88% i.e. 1.99% per month to 45.00% i.e. 3.75% per month based on Average Monthly Balance for last Quarter) from the date of withdrawal until paid. For cash advances, interest is charged from the date of the transaction until the date of payment; there is no interest free period for cash advances.', 'Total Amount Due Rs. 0-250: Rs. 0; Rs. 251-1000: Rs. 250; Rs. 1001-5000: Rs. 500; Rs. 5001-25000: Rs. 1,000; Rs. 25001 & above: Rs. 1,250 (w.e.f. 20th August 2024)', '3-2-1 structure: 3x rewards on Electronics & Apparel, 2x on Entertainment, 1x on other categories', 'Complimentary domestic lounge access – spend INR 20,000+ in a quarter to get 1 domestic lounge visit the next quarter', 'Amazon Pay e-Voucher worth ₹200 on minimum spend of ₹3,000 in first 30 days', ARRAY['3-2-1 structure: 3x rewards on Electronics & Apparel, 2x on Entertainment, 1x on other categories','Complimentary domestic lounge access – spend INR 20,000+ in a quarter to get 1 domestic lounge visit the next quarter','Amazon Pay e-Voucher worth ₹200 on minimum spend of ₹3,000 in first 30 days']::text[], 'Lifetime free card for young spenders', 'https://creditcards.federalbank.co.in', 'https://www.federal.bank.in/credit-cards-mitc', 'SCHEDULE OF CHARGES/TAXES table, Joining Fee / Annual Membership fee rows, Signet column', '2026-06-26', 'needs_review', 'matched', false, now())
